import React, { useState } from 'react';
import ImportDataSidebar from './ImportDataSidebar'; 
import './ChatBox.css';
import SideNav from './SideNav';
import { useNavigate } from 'react-router-dom';

function ChatBox() {
  const [userStory, setUserStory] = useState(''); 
  const [storyDetails, setStoryDetails] = useState(null); // Store complete story details here
  const [messages, setMessages] = useState([]); 
  const [isSidebarVisible, setIsSidebarVisible] = useState(false); 
  const [jiraData, setJiraData] = useState([]); 
  const [isAuthenticated, setIsAuthenticated] = useState(true); 
  const [isProcessing, setIsProcessing] = useState(false); 
  const navigate = useNavigate(); 

  const logout = () => {
    setIsAuthenticated(false);
    navigate('/Login');
  };

  // Function to generate test cases from the backend
  const generateTestCases = async (userStoryData) => {
    setIsProcessing(true);
  
    console.log('Sending userStory data:', userStoryData);
  
    try {
      const response = await fetch('https://localhost:7216/api/UserStoryDescription/GenerateTestCases', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ userStory: userStoryData }),
      });
  
      // Check if the response status is OK (2xx)
      if (!response.ok) {
        const errorData = await response.text(); // Get the response as text if it's not JSON
        console.error('Error response from server:', errorData);
        throw new Error(`Failed to generate test cases. Status code: ${response.status}`);
      }
  
      // Check the Content-Type header (it may be missing or incorrect)
      const contentType = response.headers.get("Content-Type");
      console.log("Response Content-Type:", contentType);
  
      // Attempt to parse JSON even if the Content-Type is missing or incorrect
      let responseData;
      if (contentType && contentType.includes("application/json")) {
        responseData = await response.json(); // Safe to parse as JSON
      } else {
        // If Content-Type is not JSON, try parsing the body manually
        const textData = await response.text(); // Parse it as text
        try {
          responseData = JSON.parse(textData); // Attempt to parse as JSON manually
        } catch (e) {
          throw new Error("Response is not in valid JSON format.");
        }
      }
  
      console.log('Response Data:', responseData);
      const candidates = responseData.candidates;
  
      if (candidates && candidates.length > 0) {
        const testCaseContent = candidates[0].content.parts.map(part => part.text).join('\n');
        setMessages((prevMessages) => [
          ...prevMessages,
          { text: `Generated test cases:\n${testCaseContent}`, isUserMessage: false },
        ]);
      } else {
        setMessages((prevMessages) => [
          ...prevMessages,
          { text: 'No test cases found.', isUserMessage: false },
        ]);
      }
    } catch (error) {
      console.error('Error generating test cases:', error);
      setMessages((prevMessages) => [
        ...prevMessages,
        { text: `Error generating test cases. Error: ${error.message}`, isUserMessage: false },
      ]);
    } finally {
      setIsProcessing(false);
    }
  };      

  // Handle sending user story and generating test cases
  const handleSendMessage = () => {
    let messageText = userStory;

    // If a user story is selected, only send the description
    if (storyDetails) {
      messageText = storyDetails.description; // Only send the description
    }

    setMessages((prevMessages) => [
      ...prevMessages,
      { text: messageText, isUserMessage: true },
    ]);
    setUserStory(''); // Clear input field after sending
    generateTestCases(messageText); 
  };

  // Fetch data from Jira and populate sidebar
  const handleImportData = async () => {
    const backendUrl = 'https://localhost:7216/api/UserStoryDescription/ExportAllUserStories';
  
    try {
      const response = await fetch(backendUrl, {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json',
        },
      });
  
      if (!response.ok) {
        throw new Error('Failed to fetch data from backend');
      }
  
      const data = await response.json();
      const stories = data.map(issue => ({
        key: issue.key,
        summary: issue.summary,
        reporter: issue.reporter,
        description: issue.description
      }));
  
      setJiraData(stories); 
      setIsSidebarVisible(true); 
    } catch (error) {
      console.error('Error fetching Jira data:', error);
      setMessages((prevMessages) => [
        ...prevMessages,
        { text: 'Error fetching Jira data. Please try again later.', isUserMessage: false },
      ]);
    }
  };

  // Handle selecting user story from sidebar
  const handleSelectUserStory = (story) => {
    // Store the entire story details in state (but do not send summary in chat)
    setStoryDetails({
      summary: story.summary, // Not sent
      description: story.description, // This will be sent
      reporter: story.reporter
    });

    // Clear the input since the user is selecting a story
    setUserStory(''); 
  };  

  // Handle closing sidebar
  const handleCloseSidebar = () => {
    setIsSidebarVisible(false); 
  };

  return (
    <div className="chat-container">
      {isAuthenticated && <SideNav logout={logout} />}

      <div className="chat-box">
        <div className="chat-box-messages">
          {messages.map((message, index) => (
            <div key={index} className={`message ${message.isUserMessage ? 'user-message' : 'bot-message'}`}>
              {message.text}
            </div>
          ))}
        </div>
        <div className="chat-input-container">
          <textarea
            value={userStory}
            onChange={(e) => setUserStory(e.target.value)}
            placeholder="Type your user story or select one from the sidebar..."
            rows="6"
            disabled={isProcessing} // Still disable during processing
          />
          <button onClick={handleSendMessage} disabled={isProcessing}>Send</button>
        </div>
      </div>

      {/* Sidebar for importing Jira data */}
      {isSidebarVisible && (
        <ImportDataSidebar
          jiraData={jiraData}
          onSelectUserStory={handleSelectUserStory}
          onClose={handleCloseSidebar}
          isSidebarVisible={isSidebarVisible}
        />
      )}

      <button className="import-btn" onClick={handleImportData} disabled={isProcessing}>
        Import Data from Jira
      </button>
    </div>
  );
}

export default ChatBox;
